import{_ as t,o as s,c as r,ai as a}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Les pronoms personnels","description":"","frontmatter":{},"headers":[],"relativePath":"module-2-construire-une-phrase/pronoms-personnels.md","filePath":"module-2-construire-une-phrase/pronoms-personnels.md","lastUpdated":1773233444000}'),l={name:"module-2-construire-une-phrase/pronoms-personnels.md"};function i(n,e,o,d,c,m){return s(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="les-pronoms-personnels" tabindex="-1">Les pronoms personnels <a class="header-anchor" href="#les-pronoms-personnels" aria-label="Permalink to “Les pronoms personnels”">​</a></h1><p><strong>Prérequis :</strong> <a href="./verbes-irreguliers.html">Les verbes irréguliers</a></p><p><strong>Objectif :</strong> maitriser tous les pronoms personnels sujets et comprendre la distinction tu/vous.</p><p>Les pronoms personnels sujets ont deja ete vus dans les lecons precedentes. Cette lecon les rassemble et explique les distinctions importantes.</p><h2 id="tableau-complet" tabindex="-1">Tableau complet <a class="header-anchor" href="#tableau-complet" aria-label="Permalink to “Tableau complet”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Pronom</th><th class="p-3 text-left font-semibold text-gray-600">Traduction</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">ich</td><td class="p-3 text-gray-600">je</td><td class="p-3 text-gray-500 italic">Ich komme aus Frankreich.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">du</td><td class="p-3 text-gray-600">tu (informel)</td><td class="p-3 text-gray-500 italic">Du lernst Deutsch.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">er</td><td class="p-3 text-gray-600">il (masculin)</td><td class="p-3 text-gray-500 italic">Er ist mein Freund.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">sie</td><td class="p-3 text-gray-600">elle (feminin)</td><td class="p-3 text-gray-500 italic">Sie arbeitet viel.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">es</td><td class="p-3 text-gray-600">il/elle (neutre)</td><td class="p-3 text-gray-500 italic">Es regnet. - Il pleut.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">wir</td><td class="p-3 text-gray-600">nous</td><td class="p-3 text-gray-500 italic">Wir wohnen in Berlin.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">ihr</td><td class="p-3 text-gray-600">vous (informel pluriel)</td><td class="p-3 text-gray-500 italic">Ihr seid meine Freunde.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">sie</td><td class="p-3 text-gray-600">ils/elles</td><td class="p-3 text-gray-500 italic">Sie kommen morgen.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">Sie</td><td class="p-3 text-gray-600">vous (formel)</td><td class="p-3 text-gray-500 italic">Kommen Sie bitte herein.</td></tr></tbody></table></div><h2 id="la-distinction-du-ihr-sie" tabindex="-1">La distinction du/ihr/Sie <a class="header-anchor" href="#la-distinction-du-ihr-sie" aria-label="Permalink to “La distinction du/ihr/Sie”">​</a></h2><p>C&#39;est le point le plus important et le plus different du francais.</p><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-blue-200 bg-blue-50"><div class="font-semibold text-blue-800 text-lg">du</div><div class="text-sm text-blue-700 mt-1">Tutoiement singulier - amis, famille, enfants, collegues proches</div><div class="text-sm text-gray-600 italic mt-2">*Wie heißt du ?* - Comment tu t&#39;appelles ?</div></div><div class="p-4 rounded-xl border border-purple-200 bg-purple-50"><div class="font-semibold text-purple-800 text-lg">ihr</div><div class="text-sm text-purple-700 mt-1">Tutoiement pluriel - on s&#39;adresse a plusieurs personnes qu&#39;on tutoyerait individuellement</div><div class="text-sm text-gray-600 italic mt-2">*Kommt ihr heute Abend ?* - Vous venez ce soir ? (a des amis)</div></div><div class="p-4 rounded-xl border border-orange-200 bg-orange-50"><div class="font-semibold text-orange-800 text-lg">Sie</div><div class="text-sm text-orange-700 mt-1">Vouvoiement - singulier et pluriel. Personnes inconnues, superieurs, contextes professionnels formels. Toujours avec majuscule.</div><div class="text-sm text-gray-600 italic mt-2">*Wie heißen Sie ?* - Comment vous appelez-vous ?</div></div></div><div class="tip custom-block"><p class="custom-block-title">Quand utiliser du ou Sie ?</p><p>En Allemagne, la tendance est au tutoiement dans beaucoup de contextes (startups, magasins comme Ikea). Mais dans le doute - et surtout face a une personne plus agee ou dans un contexte formel - commence par <em>Sie</em>. La personne te proposera de passer au <em>du</em> si elle le souhaite : <em>&quot;Wir können uns duzen&quot;</em>.</p></div><h2 id="er-sie-es-selon-le-genre-grammatical" tabindex="-1">er, sie, es selon le genre grammatical <a class="header-anchor" href="#er-sie-es-selon-le-genre-grammatical" aria-label="Permalink to “er, sie, es selon le genre grammatical”">​</a></h2><p>En allemand, <em>er/sie/es</em> suivent le genre grammatical du nom, pas le sexe naturel.</p><ul><li><em>der Tisch</em> (la table, masculin) → <em>Er ist groß.</em> - Il est grand.</li><li><em>die Lampe</em> (la lampe, feminin) → <em>Sie ist hell.</em> - Elle est lumineuse.</li><li><em>das Kind</em> (l&#39;enfant, neutre) → <em>Es spielt.</em> - Il/elle joue.</li></ul><div class="warning custom-block"><p class="custom-block-title">das Madchen - elle est &quot;es&quot;</p><p><em>das Madchen</em> (la fille) est neutre grammaticalement (car diminutif en -chen). On dit donc <em>es</em> pour le designer, meme si c&#39;est une fille. C&#39;est deroutant au debut mais logique une fois qu&#39;on connait les genres.</p></div>',14)])])}const g=t(l,[["render",i]]);export{p as __pageData,g as default};
